<script setup lang="ts">
import { ref,watch } from 'vue';import { realtimeApi } from '@/api/realtime';import type { LocationSearchResult } from '@/api/types'
const props=defineProps<{modelValue:string;selectedId?:string}>(),emit=defineEmits<{ 'update:modelValue':[value:string]; 'update:selectedId':[value:string|undefined]; selected:[value:LocationSearchResult] }>();const results=ref<LocationSearchResult[]>([]),busy=ref(false),error=ref(''),lastSelected=ref('');watch(()=>props.modelValue,value=>{if(value!==lastSelected.value){emit('update:selectedId',undefined);results.value=[]}})
async function search(){const q=props.modelValue.trim();if(q.length<2){error.value='请输入至少 2 个字符';return}busy.value=true;error.value='';try{results.value=await realtimeApi.searchLocations(q);if(!results.value.length)error.value='没有找到匹配地点，可继续使用文字目的地创建行程。'}catch(e){error.value=e instanceof Error?`${e.message}；可继续使用文字目的地创建行程。`:'地点服务暂不可用'}finally{busy.value=false}}
function choose(item:LocationSearchResult){lastSelected.value=item.displayName;emit('update:modelValue',item.displayName);emit('update:selectedId',item.locationId);emit('selected',item);results.value=[];error.value=''}
</script>
<template><div class="location-search"><div class="search-row"><input id="destination" :value="modelValue" required maxlength="200" placeholder="例如：京都" autocomplete="off" @input="emit('update:modelValue',($event.target as HTMLInputElement).value)"><button type="button" class="secondary" :disabled="busy" @click="search">{{busy?'检索中…':'搜索地点'}}</button></div><p v-if="selectedId" class="selection">✓ 已选择地点，可显示天气和附近景点</p><p v-if="error" class="form-error" role="status">{{error}}</p><ul v-if="results.length" class="location-results" aria-label="地点搜索结果"><li v-for="item in results" :key="item.locationId"><button type="button" class="location-result" @click="choose(item)"><strong>{{item.name}}</strong><span>{{item.displayName}}</span></button></li></ul><small>仅点击“搜索地点”时查询，不会逐字发送。数据 © OpenStreetMap contributors。</small></div></template>
